from prometheus_client import Counter, Histogram

TOKEN_COST = Counter(
    "llm_request_cost_dollars_total",
    "Cumulative cost in USD",
    ["model", "tenant_id"],
)
OUTPUT_TOKENS = Counter(
    "llm_output_tokens_total",
    "Output tokens generated",
    ["model", "tenant_id"],
)
INPUT_TOKENS = Counter(
    "llm_input_tokens_total",
    "Input tokens processed",
    ["model", "tenant_id"],
)

# Cost model ($/token) — update when pricing changes
COST_MODEL = {
    "meta-llama/Llama-3-70b-instruct": {
        "input_cost_per_token":  0.0000010,   # $1.00/M input tokens
        "output_cost_per_token": 0.0000100,   # $10.00/M output tokens
    },
    "meta-llama/Llama-3-8b-instruct": {
        "input_cost_per_token":  0.0000002,
        "output_cost_per_token": 0.0000002,
    },
}

def record_request_cost(model: str, tenant_id: str, input_tokens: int, output_tokens: int):
    pricing = COST_MODEL.get(model, COST_MODEL["meta-llama/Llama-3-70b-instruct"])
    cost = (
        input_tokens  * pricing["input_cost_per_token"]
        + output_tokens * pricing["output_cost_per_token"]
    )
    TOKEN_COST.labels(model=model, tenant_id=tenant_id).inc(cost)
    INPUT_TOKENS.labels(model=model, tenant_id=tenant_id).inc(input_tokens)
    OUTPUT_TOKENS.labels(model=model, tenant_id=tenant_id).inc(output_tokens)

import dataclasses
from datetime import datetime

@dataclasses.dataclass
class GPUCostTracker:
    instance_type: str
    on_demand_price_per_hr: float
    num_instances: int
    _start: float = dataclasses.field(default_factory=lambda: __import__('time').time())

    @property
    def cost_per_second(self) -> float:
        return self.on_demand_price_per_hr * self.num_instances / 3600

    def cost_since_start(self) -> float:
        elapsed = __import__('time').time() - self._start
        return elapsed * self.cost_per_second

    def cost_per_token(self, output_tok_per_sec: float) -> float:
        return self.cost_per_second / max(output_tok_per_sec, 1e-9)

# Example: p4de.24xlarge × 3 nodes
tracker = GPUCostTracker(
    instance_type="p4de.24xlarge",
    on_demand_price_per_hr=32.77,
    num_instances=3,
)
print(f"Cost/s: ${tracker.cost_per_second:.4f}")
print(f"Cost/M tokens at 1800 tok/s: ${tracker.cost_per_token(1800) * 1e6:.2f}")
# Cost/s: $0.0273
# Cost/M tokens at 1800 tok/s: $15.17
